#!/usr/bin/env node
// Run once from your frontend root:
//   node install-logo.mjs
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const PUBLIC = path.join(__dirname, 'public');
const APP    = path.join(__dirname, 'src', 'app');

const ico   = Buffer.from('',   'base64');
const logo  = Buffer.from('',  'base64');
const apple = Buffer.from('', 'base64');

fs.writeFileSync(path.join(PUBLIC, 'favicon.ico'),          ico);
fs.writeFileSync(path.join(PUBLIC, 'nexcart-logo.png'),     logo);
fs.writeFileSync(path.join(APP,    'favicon.ico'),          ico);
fs.writeFileSync(path.join(APP,    'apple-touch-icon.png'), apple);
fs.writeFileSync(path.join(APP,    'icon.png'),             logo);

console.log('\u2705  NexCart logo assets installed successfully!');
console.log('   \u2192 public/favicon.ico');
console.log('   \u2192 public/nexcart-logo.png');
console.log('   \u2192 src/app/favicon.ico');
console.log('   \u2192 src/app/apple-touch-icon.png');
console.log('   \u2192 src/app/icon.png');
